int kmeansCuda(float **feature,
               int nfeatures,
               int npoints,
               int nclusters,
               int *membership,
               float **clusters,
               int *new_centers_len,
               float **new_centers)
{
    int delta = 0;
    int i, j;

    memcpy(membership_d, membership_new, npoints * sizeof(int));
    memcpy(clusters_d, clusters[0], nclusters * nfeatures * sizeof(float));

#pragma omp parallel for schedule(static)
    for (int point_id = 0; point_id < npoints; point_id++) {
        int index = -1;
        float min_dist = FLT_MAX;

        for (int i = 0; i < nclusters; i++) {
            int cluster_base_index = i * nfeatures;
            float ans = 0.0f;

            for (int j = 0; j < nfeatures; j++) {
                int addr = point_id + j * npoints;
                float diff = feature_d[addr] - clusters_d[cluster_base_index + j];
                ans += diff * diff;
            }
            float dist = ans;

            if (dist < min_dist) {
                min_dist = dist;
                index = i;
            }
        }

        if (point_id < npoints) {
            membership_d[point_id] = index;
        }
    }

    memcpy(membership_new, membership_d, npoints * sizeof(int));

    float *block_clusters_h = (float *)malloc(num_blocks_perdim * num_blocks_perdim * nclusters * nfeatures * sizeof(float));
    int *block_deltas_h = (int *)malloc(num_blocks_perdim * num_blocks_perdim * sizeof(int));

    for (int i = 0; i < num_blocks_perdim * num_blocks_perdim; i++) {
        block_deltas_h[i] = 0;
        for (int j = 0; j < nclusters * nfeatures; j++) {
            block_clusters_h[i * nclusters * nfeatures + j] = 0.f;
        }
    }

    delta = 0;
    for (i = 0; i < npoints; i++) {
        int cluster_id = membership_new[i];
        new_centers_len[cluster_id]++;
        if (membership_new[i] != membership[i]) {
            delta++;
            membership[i] = membership_new[i];
        }
        for (j = 0; j < nfeatures; j++) {
            new_centers[cluster_id][j] += feature[i][j];
        }
    }

    for (i = 0; i < num_blocks_perdim * num_blocks_perdim; i++) {
        delta += block_deltas_h[i];
    }

    for (int j = 0; j < nclusters; j++) {
        for (int k = 0; k < nfeatures; k++) {
            block_new_centers[j * nfeatures + k] = 0.f;
        }
    }

    for (i = 0; i < num_blocks_perdim * num_blocks_perdim; i++) {
        for (int j = 0; j < nclusters; j++) {
            for (int k = 0; k < nfeatures; k++) {
                block_new_centers[j * nfeatures + k] += block_clusters_h[i * nclusters * nfeatures + j * nfeatures + k];
            }
        }
    }

    for (int j = 0; j < nclusters; j++) {
        for (int k = 0; k < nfeatures; k++)
            new_centers[j][k] = block_new_centers[j * nfeatures + k];
    }

    free(block_clusters_h);
    free(block_deltas_h);

    return delta;
}
